// V47 Input Normalizer - single output
const input = $input.all()[0].json;
const rawPayload = (input.body !== undefined) ? input.body : input;
const body = Array.isArray(rawPayload) ? (rawPayload[0] || {}) : rawPayload;
const action = (body.action || body.Action || input.action || input.Action || "create").toLowerCase();
return [{
  json: {
    ...input,
    action: action,
    isDelete: (action === 'delete'),
    Record_ID: body.Record_ID || body.id || input.Record_ID || "",
    Order_ID: body.Order_ID || input.Order_ID || "",
    Customer_Name: body.Customer_Name || input.Customer_Name || ""
  }
}];
